```class Solution {
public:
    int primePalindrome(int n) {
        int result = n;
        while (result % 2 == 0) {
            result /= 2;
        }
        while (result > 1) {
            bool isPrime = true;
            for (int i = 2; i * i <= result; i++) {
                if (result % i == 0) {
                    isPrime = false;
                    break;
                }
            }
            if (isPrime) {
                result *= -1;
                break;
            }
            result /= 2;
        }
        return result;
    }
};
